create table wksp_arunext.mtg_scryfall_card_faces (
    card_face_id    number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    scryfall_id     varchar2(36 char) not null enable,
    face_number     number(2, 0) not null enable,
    name            varchar2(500 char) not null enable,
    mana_cost       varchar2(500 char),
    type_line       varchar2(500 char),
    oracle_text     clob,
    power           varchar2(20 char),
    toughness       varchar2(20 char),
    loyalty         varchar2(20 char),
    defense         varchar2(20 char),
    artist          varchar2(500 char),
    artist_id       varchar2(36 char),
    illustration_id varchar2(36 char),
    image_uris_json json,
    raw_face_json   json not null enable
);

alter table wksp_arunext.mtg_scryfall_card_faces
    add constraint mtg_scryfall_card_faces_pk primary key ( card_face_id )
        using index enable;

alter table wksp_arunext.mtg_scryfall_card_faces
    add constraint mtg_scryfall_card_faces_uk unique ( scryfall_id,
                                                       face_number )
        using index enable;

